import json
import base64
import urllib.parse
import ipaddress
import requests

USER_AGENT = "lambda-edge-enrichment/1.0"
DEFAULT_TIMEOUT_SECONDS = 1.5
MAX_URLS = 5
MAX_RESPONSE_BYTES = 64 * 1024
ALLOWED_SCHEMES = {"https"}
ALLOW_HTTP = False
ALLOWED_HOSTS = None  # set to a set/list of allowed hostnames to restrict, e.g. {"api.example.com"}
ALLOWED_PORTS = {443}
BLOCK_PRIVATE_IPS = True

