def _get_headers_dict(cf_headers):
    out = {}
    for k, v in (cf_headers or {}).items():
        if v and isinstance(v, list) and "value" in v[0]:
            out[k.lower()] = v[0]["value"]
    return out


def _set_header(cf_headers, name, value):
    cf_headers[name.lower()] = [{"key": name, "value": value}]


def _del_header(cf_headers, name):
    cf_headers.pop(name.lower(), None)


def _parse_urls(header_value):
    if not header_value:
        return []
    parts = [p.strip() for p in header_value.split(",")]
    urls = [p for p in parts if p]
    return urls[:MAX_URLS]


def _is_private_ip(hostname):
    try:
        ip = ipaddress.ip_address(hostname)
        return ip.is_private or ip.is_loopback or ip.is_link_local or ip.is_reserved or ip.is_multicast
    except ValueError:
        return False


def _validate_url(url):
    try:
        parsed = urllib.parse.urlsplit(url)
    except Exception:
        return False, "invalid_url"

    scheme = (parsed.scheme or "").lower()
    if scheme not in ALLOWED_SCHEMES and not (ALLOW_HTTP and scheme == "http"):
        return False, "scheme_not_allowed"

    if not parsed.netloc:
        return False, "missing_host"

    hostname = parsed.hostname
    if not hostname:
        return False, "missing_hostname"

    if ALLOWED_HOSTS is not None and hostname.lower() not in {h.lower() for h in ALLOWED_HOSTS}:
        return False, "host_not_allowed"

    port = parsed.port
    if port is None:
        port = 443 if scheme == "https" else 80
    if port not in ALLOWED_PORTS and not (ALLOW_HTTP and port == 80):
        return False, "port_not_allowed"

    if BLOCK_PRIVATE_IPS and _is_private_ip(hostname):
        return False, "private_ip_blocked"

    return True, ""


def _fetch_url(url, timeout=DEFAULT_TIMEOUT_SECONDS):
    headers = {
        "User-Agent": USER_AGENT,
        "Accept": "application/json, text/plain;q=0.9, */*;q=0.1",
        "Connection": "close",
    }
    r = SESSION.get(url, headers=headers, timeout=timeout, allow_redirects=False, stream=True)
    status = r.status_code
    content_type = r.headers.get("Content-Type", "")

    data = b""
    for chunk in r.iter_content(chunk_size=4096):
        if not chunk:
            continue
        data += chunk
        if len(data) > MAX_RESPONSE_BYTES:
            data = data[:MAX_RESPONSE_BYTES]
            break

    try:
        text = data.decode("utf-8", errors="replace")
    except Exception:
        text = ""

    return {
        "url": url,
        "status": status,
        "contentType": content_type,
        "body": text,
        "truncated": len(data) >= MAX_RESPONSE_BYTES,
    }


def handler(event, context):
    cf = event["Records"][0]["cf"]
    request = cf["request"]
